    pri = Integer.parseInt(prio.toString());
    sev = pri % 8;
    facility = pri / 8;
    formatHeaders();
  }

  Map <String, String> headers = new HashMap<String, String>();
  headers.put(SYSLOG_FACILITY, String.valueOf(facility));
  headers.put(SYSLOG_SEVERITY, String.valueOf(sev));
