        result.append("\\n");
        break;
      case '\f':
        result.append("\\f");
        break;
      case '\r':
        result.append("\\r");
        break;
      default:
        if (Character.isISOControl(c)) {
          result.append(String.format("\\u%04x", (int) c));
        } else {
          result.append(c);
        }
    }
  }
  result.append('"');
  return result.toString();
}

